import React, { Component } from "react";
import { Link } from "gatsby";
import { 
  Button, 
  Card, 
  CardActions, 
  CardText, 
  CardTitle, 
  List, 
  ListItem, 
}  from "react-md";

import "./ContentCard.scss"

export default class ContentCard extends Component{
  render () {
    return (
      <Card className={`content-card ${this.props.className}`}> 
        {
          this.props.titleText ? 
            <CardTitle 
              title={this.props.titleText} 
              subtitle={this.props.subtitleText} 
              avatar={this.props.avatar}
            /> 
            : null

        }
        <CardText>
          { this.props.children }
        </CardText>
      </Card>
    );
  }
}
